import com.fasterxml.jackson.databind.ObjectMapper;
import dev.langchain4j.model.ollama.RunningOllamaModel;
import java.lang.reflect.Method;
public class VerifyRunningOllamaContextLength {
    public static void main(String[] args) throws Exception {
        String json = "{"
                + "\"name\":\"llama3.1:latest\","
                + "\"model\":\"llama3.1:latest\","
                + "\"size\":123,"
                + "\"digest\":\"abc\","
                + "\"expires_at\":\"2026-06-01T05:00:00Z\","
                + "\"size_vram\":456,"
                + "\"context_length\":4096"
                + "}";
        RunningOllamaModel model = new ObjectMapper().readValue(json, RunningOllamaModel.class);
        Method getter = RunningOllamaModel.class.getMethod("getContextLength");
        Object contextLength = getter.invoke(model);
        if (!Long.valueOf(4096).equals(contextLength)) {
            throw new AssertionError("Expected contextLength 4096 but got " + contextLength);
        }
        System.out.println("contextLength=" + contextLength);
    }
}
EOF


