import com.fasterxml.jackson.databind.ObjectMapper;
import dev.langchain4j.model.ollama.RunningOllamaModel;

public class VerifyRunningOllamaContextLength {
    public static void main(String[] args) throws Exception {
        ObjectMapper mapper = new ObjectMapper();

        RunningOllamaModel model = mapper.readValue("{"
                + "\"name\":\"llama3.1:latest\","
                + "\"model\":\"llama3.1:latest\","
                + "\"size\":123,"
                + "\"digest\":\"abc\","
                + "\"expires_at\":\"2026-06-01T05:00:00Z\","
                + "\"size_vram\":456,"
                + "\"context_length\":4096"
                + "}", RunningOllamaModel.class);
        if (!Long.valueOf(4096).equals(model.getContextLength())) {
            throw new AssertionError("Expected contextLength 4096 but got " + model.getContextLength());
        }

        RunningOllamaModel withoutContextLength = mapper.readValue("{"
                + "\"name\":\"llama3.1:latest\","
                + "\"model\":\"llama3.1:latest\""
                + "}", RunningOllamaModel.class);
        if (withoutContextLength.getContextLength() != null) {
            throw new AssertionError("Expected missing contextLength to remain null");
        }

        model.setContextLength(8192L);
        String serialized = mapper.writeValueAsString(model);
        if (!serialized.contains("\"context_length\":8192")) {
            throw new AssertionError("Expected serialized JSON to contain context_length: " + serialized);
        }

        System.out.println("contextLength checks passed");
    }
}
EOF
